module top_module(
input [31:0] Data_in,
output reg[31:0] Data_out,
input Wr, 
input Reset, 
input Clk
    );always @(posedge Clk or posedge Reset)
  wire [31:0] _tap_Data_in = Data_in & {32{1'b1}};

begin
   if (Reset)
      Data_out <= 32'b0;
   else if (Wr)
      Data_out <= Data_in;
end
endmodule
